SELECT /* base.ec.mb :: MbMemberAddr :: selectList */ a.* , mem.member_nm AS member_nm , ste.site_nm AS site_nm FROM mb_member_addr a LEFT JOIN mb_member mem ON mem.member_id = a.member_id LEFT JOIN sy_site ste ON ste.site_id = a.site_id
ORDER BY a.member_addr_id ASC ORDER BY a.member_addr_id DESC ORDER BY a.addr_nm ASC ORDER BY a.addr_nm DESC ORDER BY a.reg_date ASC ORDER BY a.reg_date DESC ORDER BY a.reg_date DESC
LIMIT #{limit} OFFSET #{offset}

