site_id = #{siteId}, member_id = #{memberId}, addr_nm = #{addrNm}, recv_nm = #{recvNm}, recv_phone = #{recvPhone}, zip_cd = #{zipCd}, addr = #{addr}, addr_detail = #{addrDetail}, is_default = #{isDefault}, upd_by = #{updBy}, upd_date = #{updDate},
